// ─── Supabase helpers ─────────────────────────────────────────────────────────
const sbFetch = (path, opts = {}) =>
  fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    ...opts,
    headers: {
      "apikey": SUPABASE_ANON,
      "Authorization": `Bearer ${SUPABASE_ANON}`,
      "Content-Type": "application/json",
      "Prefer": "return=representation",
      ...(opts.headers || {}),
    },
  });

// ─── Header ───────────────────────────────────────────────────────────────────
function Header({ date = "30 · 05 · 25" }) {
  return (
    <div style={{ borderBottom: `1px solid ${border}`, padding: "20px 32px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
      <img src={LOGO_SRC} alt="Deep On Tech" style={{ height: 28, mixBlendMode: "screen", filter: "brightness(2) grayscale(1)" }} />
      <span style={{ fontFamily: mono, fontSize: 10, letterSpacing: 2, color: "#333" }}>{date}</span>
    </div>
  );
}

// ─── Guest Page ───────────────────────────────────────────────────────────────
function GuestPage({ slug }) {
  const [guest, setGuest] = useState(null);
  const [selected, setSelected] = useState(null);
  const [confirmed, setConfirmed] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);
  const [hoveredSlot, setHoveredSlot] = useState(null);

  useEffect(() => {
    sbFetch(`guests?slug=eq.${slug}&select=*`)
      .then(r => r.json())
      .then(data => {
        if (data.length === 0) { setError("Convite não encontrado."); setLoading(false); return; }
        const g = data[0];
        setGuest(g);
        if (g.slot) { setSelected(g.slot); setConfirmed(true); }
        setLoading(false);
      })
      .catch(() => { setError("Erro ao carregar convite."); setLoading(false); });
  }, [slug]);

  const handleConfirm = async () => {
    if (!selected || saving) return;
    setSaving(true);
    await sbFetch(`guests?id=eq.${guest.id}`, {
      method: "PATCH",
      body: JSON.stringify({ slot: selected, confirmed_at: new Date().toISOString() }),
    });
    setConfirmed(true);
    setSaving(false);
  };

  if (loading) return (
    <div style={{ minHeight: "100vh", background: bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <span style={{ fontFamily: mono, fontSize: 10, letterSpacing: 3, color: "#333" }}>CARREGANDO</span>
    </div>
  );

  if (error) return (
    <div style={{ minHeight: "100vh", background: bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <span style={{ fontFamily: mono, fontSize: 11, color: "#555" }}>{error}</span>
    </div>
  );

  if (confirmed) return (
    <div style={{ minHeight: "100vh", background: bg, fontFamily: font }}>
      <Header />
      <div style={{ maxWidth: 480, margin: "0 auto", padding: "80px 24px", textAlign: "center", animation: "fadeUp 0.8s ease both" }}>
        <div style={{ width: 64, height: 64, borderRadius: "50%", border: `1px solid ${gold}`, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 32px", fontSize: 24, color: gold }}>✓</div>
        <p style={{ fontFamily: mono, fontSize: 10, letterSpacing: 4, color: gold, marginBottom: 16 }}>PRESENÇA CONFIRMADA</p>
        <h2 style={{ fontSize: 32, fontWeight: 300, marginBottom: 8 }}>{guest.name}</h2>
        <div style={{ width: 40, height: 1, background: gold, margin: "20px auto" }} />
        <p style={{ fontSize: 16, fontWeight: 300, color: "#AAA", lineHeight: 1.8 }}>
          Nos vemos no dia <span style={{ color: goldLight }}>30 de maio</span><br />
          às <span style={{ color: goldLight }}>{SLOTS.find(s => s.id === selected)?.label}</span>
        </p>
        <p style={{ marginTop: 32, fontSize: 12, color: "#444", fontFamily: mono, letterSpacing: 2 }}>THERA OFFICE BERRINI</p>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight: "100vh", background: bg, fontFamily: font }}>
      <Header />
      <div style={{ maxWidth: 480, margin: "0 auto", padding: "60px 24px 60px" }}>

        {/* Hero */}
        <div style={{ animation: "fadeUp 0.6s ease both", marginBottom: 48 }}>
          <p style={{ fontFamily: mono, fontSize: 10, letterSpacing: 4, color: gold, marginBottom: 20 }}>CONVITE ESPECIAL</p>
          <h1 style={{ fontSize: "clamp(36px,10vw,52px)", fontWeight: 300, lineHeight: 1.1, marginBottom: 6 }}>
            Opening<br /><em style={{ fontStyle: "italic", color: goldLight }}>Night</em>
          </h1>
          <div style={{ height: 1, background: `linear-gradient(90deg,${gold},transparent)`, marginTop: 20, marginBottom: 28, animation: "lineExpand 1s ease 0.4s both" }} />
          <p style={{ fontSize: 16, fontWeight: 300, color: "#AAA", lineHeight: 1.9 }}>
            É com grande prazer que abrimos as portas do nosso Showroom para você, <span style={{ color: "#E8E0D4" }}>{guest.name.split(" ")[0]}</span>. Para que sua experiência seja única e personalizada, escolha o horário em que prefere ser recebido.
          </p>
        </div>

        {/* Event details */}
        <div style={{ animation: "fadeUp 0.6s ease 0.2s both", border: `1px solid ${border}`, padding: "24px 28px", marginBottom: 40, background: surface }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, marginBottom: 20 }}>
            <div>
              <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 3, color: "#444", marginBottom: 6 }}>DATA</p>
              <p style={{ fontSize: 18 }}>30 de Maio</p>
              <p style={{ fontSize: 12, color: "#666", fontFamily: mono, letterSpacing: 1 }}>SÁBADO</p>
            </div>
            <div>
              <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 3, color: "#444", marginBottom: 6 }}>ABERTURA</p>
              <p style={{ fontSize: 18 }}>16h</p>
              <p style={{ fontSize: 12, color: "#666", fontFamily: mono, letterSpacing: 1 }}>ATÉ 22H</p>
            </div>
          </div>
          <div style={{ borderTop: `1px solid ${border}`, paddingTop: 20 }}>
            <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 3, color: "#444", marginBottom: 6 }}>LOCAL</p>
            <p style={{ fontSize: 15, color: goldLight }}>Thera Office Berrini</p>
            <p style={{ fontSize: 13, color: "#666", lineHeight: 1.6, marginTop: 4 }}>
              Av. Eng. Luís Carlos Berrini, 105 — CJ 1703<br />
              <span style={{ color: "#444", fontSize: 12 }}>Valet disponível no local</span>
            </p>
          </div>
        </div>

        {/* Slot selection */}
        <div style={{ animation: "fadeUp 0.6s ease 0.4s both" }}>
          <p style={{ fontFamily: mono, fontSize: 10, letterSpacing: 3, color: "#555", marginBottom: 20 }}>EM QUAL JANELA PRETENDE CHEGAR?</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 32 }}>
            {SLOTS.map(slot => {
              const isSel = selected === slot.id;
              const isHov = hoveredSlot === slot.id;
              return (
                <button key={slot.id} onClick={() => setSelected(slot.id)}
                  onMouseEnter={() => setHoveredSlot(slot.id)} onMouseLeave={() => setHoveredSlot(null)}
                  style={{ background: isSel ? "rgba(200,151,58,0.1)" : isHov ? "rgba(255,255,255,0.02)" : "transparent", border: `1px solid ${isSel ? gold : isHov ? "#333" : border}`, color: isSel ? goldLight : "#888", padding: "14px 20px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "space-between", fontFamily: font, fontSize: 16, fontWeight: 300, transition: "all 0.2s ease" }}>
                  <span>{slot.label}</span>
                  <span style={{ width: 16, height: 16, border: `1px solid ${isSel ? gold : "#333"}`, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, color: gold, background: isSel ? "rgba(200,151,58,0.2)" : "transparent", transition: "all 0.2s ease" }}>{isSel ? "●" : ""}</span>
                </button>
              );
            })}
          </div>
          <button onClick={handleConfirm} disabled={!selected || saving}
            style={{ width: "100%", padding: "18px", background: selected ? `linear-gradient(135deg,${gold},#A07828)` : "#1A1A1A", border: "none", color: selected ? "#0A0A0A" : "#333", fontFamily: mono, fontSize: 11, letterSpacing: 4, cursor: selected ? "pointer" : "not-allowed", transition: "all 0.3s ease", fontWeight: 600 }}>
            {saving ? "CONFIRMANDO..." : "CONFIRMAR PRESENÇA"}
          </button>
          <p style={{ textAlign: "center", marginTop: 20, fontSize: 12, color: "#333", fontFamily: mono, letterSpacing: 1 }}>Uma experiência. Uma noite. Uma nova era.</p>
        </div>
      </div>
    </div>
  );
}

// ─── Admin Panel ──────────────────────────────────────────────────────────────
function AdminPanel() {
  const [guests, setGuests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("overview");
  const [newName, setNewName] = useState("");
  const [adding, setAdding] = useState(false);

  const load = () =>
    sbFetch("guests?select=*&order=name.asc")
      .then(r => r.json())
      .then(data => { setGuests(data); setLoading(false); });

  useEffect(() => { load(); }, []);

  const addGuest = async () => {
    if (!newName.trim() || adding) return;
    setAdding(true);
    const slug = newName.trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");
    await sbFetch("guests", { method: "POST", body: JSON.stringify({ name: newName.trim(), slug }) });
    setNewName("");
    setAdding(false);
    load();
  };

  const removeGuest = async (id) => {
    await sbFetch(`guests?id=eq.${id}`, { method: "DELETE", headers: { "Prefer": "return=minimal" } });
    load();
  };

  const confirmed = guests.filter(g => g.slot);
  const pending = guests.filter(g => !g.slot);
  const slotCounts = SLOTS.map(s => ({ ...s, guests: guests.filter(g => g.slot === s.id), count: guests.filter(g => g.slot === s.id).length }));

  const baseUrl = "https://showroom.deepon.tech";

  if (loading) return (
    <div style={{ minHeight: "100vh", background: bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <span style={{ fontFamily: mono, fontSize: 10, letterSpacing: 3, color: "#333" }}>CARREGANDO</span>
    </div>
  );

  return (
    <div style={{ minHeight: "100vh", background: bg, fontFamily: font }}>
      <div style={{ borderBottom: `1px solid ${border}`, padding: "20px 32px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
          <img src={LOGO_SRC} alt="Deep On Tech" style={{ height: 24, mixBlendMode: "screen", filter: "brightness(2) grayscale(1)" }} />
          <span style={{ fontFamily: mono, fontSize: 9, letterSpacing: 3, color: "#333" }}>/ ADMIN</span>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {["overview", "convidados", "horários"].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} style={{ background: activeTab === tab ? "rgba(200,151,58,0.1)" : "transparent", border: `1px solid ${activeTab === tab ? gold : border}`, color: activeTab === tab ? gold : "#555", padding: "6px 14px", fontFamily: mono, fontSize: 9, letterSpacing: 2, cursor: "pointer", textTransform: "uppercase" }}>{tab}</button>
          ))}
        </div>
      </div>

      <div style={{ maxWidth: 800, margin: "0 auto", padding: "40px 24px" }}>

        {/* Adicionar convidado */}
        <div style={{ display: "flex", gap: 8, marginBottom: 40 }}>
          <input value={newName} onChange={e => setNewName(e.target.value)}
            onKeyDown={e => e.key === "Enter" && addGuest()}
            placeholder="Nome do convidado..."
            style={{ flex: 1, background: surface, border: `1px solid ${border}`, color: "#E8E0D4", padding: "12px 16px", fontFamily: font, fontSize: 15, outline: "none" }} />
          <button onClick={addGuest} disabled={adding || !newName.trim()}
            style={{ background: newName.trim() ? `linear-gradient(135deg,${gold},#A07828)` : "#1A1A1A", border: "none", color: newName.trim() ? "#0A0A0A" : "#333", padding: "12px 20px", fontFamily: mono, fontSize: 9, letterSpacing: 2, cursor: "pointer" }}>
            {adding ? "..." : "ADICIONAR"}
          </button>
        </div>

        {/* Overview */}
        {activeTab === "overview" && (
          <div style={{ animation: "fadeUp 0.4s ease both" }}>
            <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 4, color: "#444", marginBottom: 32 }}>OPENING NIGHT — 30/05</p>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 16, marginBottom: 40 }}>
              {[{ label: "Convidados", value: guests.length, color: "#E8E0D4" }, { label: "Confirmados", value: confirmed.length, color: gold }, { label: "Aguardando", value: pending.length, color: "#555" }].map(s => (
                <div key={s.label} style={{ border: `1px solid ${border}`, padding: "24px 20px", background: surface }}>
                  <p style={{ fontFamily: mono, fontSize: 8, letterSpacing: 3, color: "#444", marginBottom: 12 }}>{s.label.toUpperCase()}</p>
                  <p style={{ fontSize: 40, fontWeight: 300, color: s.color, lineHeight: 1 }}>{s.value}</p>
                </div>
              ))}
            </div>
            <div style={{ marginBottom: 8, display: "flex", justifyContent: "space-between" }}>
              <span style={{ fontFamily: mono, fontSize: 9, letterSpacing: 2, color: "#444" }}>CONFIRMAÇÕES</span>
              <span style={{ fontFamily: mono, fontSize: 9, color: gold }}>{guests.length ? Math.round((confirmed.length / guests.length) * 100) : 0}%</span>
            </div>
            <div style={{ height: 2, background: border, marginBottom: 40 }}>
              <div style={{ height: "100%", background: `linear-gradient(90deg,${gold},${goldLight})`, width: guests.length ? `${(confirmed.length / guests.length) * 100}%` : "0%", transition: "width 0.5s ease" }} />
            </div>
            <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 3, color: "#444", marginBottom: 16 }}>DISTRIBUIÇÃO POR JANELA</p>
            {slotCounts.map(slot => (
              <div key={slot.id} style={{ display: "flex", alignItems: "center", gap: 16, padding: "12px 16px", border: `1px solid ${border}`, background: surface, marginBottom: 4 }}>
                <span style={{ fontFamily: mono, fontSize: 10, color: "#555", width: 80, flexShrink: 0 }}>{slot.id}H</span>
                <div style={{ flex: 1, height: 1, background: border, position: "relative" }}>
                  {slot.count > 0 && <div style={{ position: "absolute", top: -3, left: 0, height: 7, background: gold, width: `${(slot.count / Math.max(guests.length, 1)) * 100}%`, transition: "width 0.5s ease" }} />}
                </div>
                <span style={{ fontFamily: mono, fontSize: 11, color: slot.count > 0 ? gold : "#333", width: 24, textAlign: "right" }}>{slot.count}</span>
              </div>
            ))}
          </div>
        )}

        {/* Convidados */}
        {activeTab === "convidados" && (
          <div style={{ animation: "fadeUp 0.4s ease both" }}>
            <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 4, color: "#444", marginBottom: 24 }}>LISTA DE CONVIDADOS</p>
            <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
              {guests.map(g => (
                <div key={g.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 20px", background: surface, borderLeft: `2px solid ${g.slot ? gold : border}` }}>
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: 16, fontWeight: 300 }}>{g.name}</p>
                    {g.slot && <p style={{ fontFamily: mono, fontSize: 9, color: "#555", letterSpacing: 2, marginTop: 2 }}>{SLOTS.find(s => s.id === g.slot)?.label}</p>}
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <button onClick={() => { navigator.clipboard.writeText(`${baseUrl}/convite/${g.slug}`); }}
                      style={{ background: "transparent", border: `1px solid ${border}`, color: "#555", padding: "4px 10px", fontFamily: mono, fontSize: 8, letterSpacing: 1, cursor: "pointer" }}>
                      COPIAR LINK
                    </button>
                    <div style={{ fontFamily: mono, fontSize: 8, letterSpacing: 2, padding: "4px 10px", border: `1px solid ${g.slot ? gold : border}`, color: g.slot ? gold : "#333" }}>
                      {g.slot ? "CONFIRMADO" : "PENDENTE"}
                    </div>
                    <button onClick={() => removeGuest(g.id)}
                      style={{ background: "transparent", border: "none", color: "#333", cursor: "pointer", fontSize: 16, lineHeight: 1 }}>×</button>
                  </div>
                </div>
              ))}
              {guests.length === 0 && <p style={{ fontFamily: mono, fontSize: 10, color: "#333", textAlign: "center", padding: "40px 0" }}>Nenhum convidado cadastrado ainda.</p>}
            </div>
          </div>
        )}

        {/* Horários */}
        {activeTab === "horários" && (
          <div style={{ animation: "fadeUp 0.4s ease both" }}>
            <p style={{ fontFamily: mono, fontSize: 9, letterSpacing: 4, color: "#444", marginBottom: 24 }}>APRESENTAÇÕES POR JANELA</p>
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              {slotCounts.map(slot => (
                <div key={slot.id} style={{ border: `1px solid ${slot.count > 0 ? border : "#141414"}`, background: slot.count > 0 ? surface : "transparent" }}>
                  <div style={{ padding: "14px 20px", borderBottom: slot.count > 0 ? `1px solid ${border}` : "none", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <span style={{ fontSize: 18, fontWeight: 300, color: slot.count > 0 ? goldLight : "#333" }}>{slot.label}</span>
                    <span style={{ fontFamily: mono, fontSize: 10, color: slot.count > 0 ? gold : "#2A2A2A" }}>{slot.count} {slot.count === 1 ? "convidado" : "convidados"}</span>
                  </div>
                  {slot.guests.length > 0 && (
                    <div style={{ padding: "12px 20px", display: "flex", flexWrap: "wrap", gap: 8 }}>
                      {slot.guests.map(g => (
                        <span key={g.id} style={{ fontFamily: mono, fontSize: 10, letterSpacing: 1, color: "#888", padding: "4px 10px", border: `1px solid ${border}` }}>{g.name}</span>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Router ───────────────────────────────────────────────────────────────────
export default function App() {
  const [view, setView] = useState("admin");
  const [slug, setSlug] = useState("");

  // Simple hash-based routing: #/convite/slug or #/admin
  useEffect(() => {
    const parse = () => {
      const hash = window.location.hash.replace("#", "");
      if (hash.startsWith("/convite/")) {
        setSlug(hash.replace("/convite/", ""));
        setView("guest");
      } else {
        setView("admin");
      }
    };
    parse();
    window.addEventListener("hashchange", parse);
    return () => window.removeEventListener("hashchange", parse);
  }, []);

  return (
    <>
      <style>{globalStyles}</style>
      {view === "guest" ? <GuestPage slug={slug} /> : <AdminPanel />}
    </>
  );
}
